class Solution(object):
    def isCompleteTree(self, root):
        from collections import deque
        queue = deque([root])
        found_null = False
        while queue:
            node = queue.popleft()
            if not node:
                found_null = True
            else:
                if found_null:
                    return False
                queue.append(node.left)
                queue.append(node.right)
        return True
